class Solution(object):
    def containsCycle(self, grid):
        m, n = len(grid), len(grid[0])
        visited = set()
        def dfs(r, c, pr, pc):
            if (r, c) in visited:
                return True
            visited.add((r, c))
            for dr, dc in [(0,1), (1,0), (0,-1), (-1,0)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] == grid[r][c]:
                    if (nr, nc) != (pr, pc):
                        if dfs(nr, nc, r, c):
                            return True
            return False
        for i in range(m):
            for j in range(n):
                if (i, j) not in visited:
                    if dfs(i, j, -1, -1):
                        return True
        return False
